PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?dynasty ?dynastyLabel WHERE {
  ?dynasty wdt:P31 wd:Q151495 .
  ?dynasty wdt:P140 wd:Q172090 .
  ?dynasty wdt:P17 ?country .
  ?country wdt:P361 ?region .
  VALUES ?region {
    wd:Q549 wd:Q42600
  }
  OPTIONAL {
    ?dynasty rdfs:label ?dynastyLabel .
    FILTER(LANG(?dynastyLabel) = 'en')
  }
}

